  1→import { useEffect, useState, useCallback } from "react";
  2→import { DailyDashboard } from "./components/DailyDashboard";
  3→import { SessionTimeline } from "./components/SessionTimeline";
  4→import {
  5→  fetchDailyStats,
  6→  fetchSessions,
  7→  fetchRepos,
  8→  addRepo,
  9→  deleteRepo,
 10→  syncData,
 11→} from "./api";
 12→import type { DailyStat, Repository, Session } from "./types";
 13→import "./App.css";
 14→
 15→function App() {
 16→  const [repos, setRepos] = useState<Repository[]>([]);
 17→  const [selectedRepo, setSelectedRepo] = useState<string>("");
 18→  const [dailyStats, setDailyStats] = useState<DailyStat[]>([]);
 19→  const [sessions, setSessions] = useState<Session[]>([]);
 20→  const [syncing, setSyncing] = useState(false);
 21→  const [lastSynced, setLastSynced] = useState<string>("");
 22→  const [newRepoPath, setNewRepoPath] = useState("");
 23→  const [addingRepo, setAddingRepo] = useState(false);
 24→  const [showRepoForm, setShowRepoForm] = useState(false);
 25→  const [loadError, setLoadError] = useState<string>("");
 26→
 27→  const loadRepos = useCallback(async () => {
 28→    try {
 29→      const r = await fetchRepos();
 30→      setRepos(r);
 31→    } catch (e) {
 32→      setRepos([]);
 33→      setLoadError(e instanceof Error ? e.message : "リポジトリ取得に失敗しました");
 34→    }
 35→  }, []);
 36→
 37→  const loadData = useCallback(async () => {
 38→    try {
 39→      setLoadError("");
 40→      const repoFilter = selectedRepo || undefined;
 41→      const [stats, sess] = await Promise.all([
 42→        fetchDailyStats(repoFilter),
 43→        fetchSessions(repoFilter),
 44→      ]);
 45→      setDailyStats(stats);
 46→      setSessions(sess);
 47→    } catch (e) {
 48→      setDailyStats([]);
 49→      setSessions([]);
 50→      setLoadError(e instanceof Error ? e.message : "データ取得に失敗しました");
 51→    }
 52→  }, [selectedRepo]);
 53→
 54→  useEffect(() => {
 55→    loadRepos();
 56→  }, [loadRepos]);
 57→
 58→  useEffect(() => {
 59→    loadData();
 60→  }, [loadData]);
 61→
 62→  const handleSync = async () => {
 63→    setSyncing(true);
 64→    try {
 65→      const repoFilter = selectedRepo || undefined;
 66→      await syncData(repoFilter);
 67→      setLastSynced(new Date().toLocaleString("ja-JP"));
 68→      await loadData();
 69→    } catch {
 70→      setLastSynced("Sync failed");
 71→    } finally {
 72→      setSyncing(false);
 73→    }
 74→  };
 75→
 76→  const handleAddRepo = async () => {
 77→    if (addingRepo || !newRepoPath.trim()) return;
 78→    setAddingRepo(true);
 79→    try {
 80→      await addRepo(newRepoPath.trim());
 81→      setNewRepoPath("");
 82→      setShowRepoForm(false);
 83→      await loadRepos();
 84→    } catch (e) {
 85→      alert(`Failed to add repo: ${e instanceof Error ? e.message : e}`);
 86→    } finally {
 87→      setAddingRepo(false);
 88→    }
 89→  };
 90→
 91→  const handleDeleteRepo = async (id: number) => {
 92→    try {
 93→      const target = repos.find((r) => r.id === id);
 94→      await deleteRepo(id);
 95→      await loadRepos();
 96→      if (target?.path === selectedRepo) {
 97→        setSelectedRepo("");
 98→      }
 99→    } catch (e) {
100→      alert(`Failed to delete repo: ${e instanceof Error ? e.message : e}`);
101→    }
102→  };
103→
104→  // Compute KPIs
105→  const totalAgent = dailyStats.reduce((sum, d) => sum + d.agent_lines, 0);
106→  const totalHuman = dailyStats.reduce((sum, d) => sum + d.human_lines, 0);
107→  const totalAll = totalAgent + totalHuman;
108→  const overallPct =
109→    totalAll > 0 ? ((totalAgent / totalAll) * 100).toFixed(1) : "0.0";
110→  const totalSessions = sessions.length;
111→
112→  return (
113→    <div className="dashboard">
114→      <header className="header">
115→        <h1 className="header-title">Entire Dashboard</h1>
116→        <div className="header-actions">
117→          {lastSynced && (
118→            <span className="sync-status">Last synced: {lastSynced}</span>
119→          )}
120→          <button
121→            onClick={handleSync}
122→            disabled={syncing}
123→            className="sync-button"
124→          >
125→            {syncing ? "Syncing..." : "Sync"}
126→          </button>
127→        </div>
128→      </header>
129→
130→      {/* Repository Selector */}
131→      <div className="repo-bar">
132→        <div className="repo-selector">
133→          <select
134→            value={selectedRepo}
135→            onChange={(e) => setSelectedRepo(e.target.value)}
136→            className="repo-select"
137→          >
138→            <option value="">All Repositories</option>
139→            {repos.map((r) => (
140→              <option key={r.id} value={r.path}>
141→                {r.name} ({r.path})
142→              </option>
143→            ))}
144→          </select>
145→
146→          <button
147→            className="repo-add-button"
148→            onClick={() => setShowRepoForm(!showRepoForm)}
149→          >
150→            + Add
151→          </button>
152→        </div>
153→
154→        {showRepoForm && (
155→          <div className="repo-form">
156→            <input
157→              type="text"
158→              value={newRepoPath}
159→              onChange={(e) => setNewRepoPath(e.target.value)}
160→              onKeyDown={(e) => e.key === "Enter" && handleAddRepo()}
161→              placeholder="/path/to/git/repository"
162→              className="repo-input"
163→              disabled={addingRepo}
164→            />
165→            <button
166→              onClick={handleAddRepo}
167→              disabled={addingRepo || !newRepoPath.trim()}
168→              className="sync-button"
169→            >
170→              {addingRepo ? "Adding..." : "Add"}
171→            </button>
172→          </div>
173→        )}
174→
175→        {repos.length > 0 && (
176→          <div className="repo-list">
177→            {repos.map((r) => (
178→              <div key={r.id} className="repo-tag">
179→                <span className="repo-tag-name">{r.name}</span>
180→                <span className="repo-tag-path">{r.path}</span>
181→                <button
182→                  className="repo-tag-delete"
183→                  onClick={() => handleDeleteRepo(r.id)}
184→                  title="Remove repository"
185→                  aria-label={`${r.name} を削除`}
186→                >
187→                  &times;
188→                </button>
189→              </div>
190→            ))}
191→          </div>
192→        )}
193→      </div>
194→
195→      {loadError && (
196→        <div style={{ color: "#d32f2f", background: "#fdecea", padding: "12px 16px", borderRadius: 8, marginBottom: 16, fontSize: 13 }}>
197→          {loadError}
198→        </div>
199→      )}
200→
201→      {/* KPI: Overview indicators */}
202→      <div className="kpi-row">
203→        <div className="kpi-card kpi-card--primary">
204→          <div className="kpi-label">AI Contribution Ratio</div>
205→          <div className="kpi-value">
206→            {overallPct}
207→            <span className="kpi-unit">%</span>
208→          </div>
209→        </div>
210→        <div className="kpi-card">
211→          <div className="kpi-label">AI Lines</div>
212→          <div className="kpi-value">{totalAgent.toLocaleString()}</div>
213→        </div>
214→        <div className="kpi-card">
215→          <div className="kpi-label">Human Lines</div>
216→          <div className="kpi-value">{totalHuman.toLocaleString()}</div>
217→        </div>
218→        <div className="kpi-card">
219→          <div className="kpi-label">Sessions</div>
220→          <div className="kpi-value">{totalSessions}</div>
221→        </div>
222→      </div>
223→
224→      {/* Daily Chart: Trend over time */}
225→      <DailyDashboard data={dailyStats} />
226→
227→      {/* Session Detail: Individual session breakdown */}
228→      <SessionTimeline sessions={sessions} />
229→    </div>
230→  );
231→}
232→
233→export default App;
234→

 1→import type { DailyStat, Repository, Session } from "./types";
 2→
 3→const BASE = "http://localhost:8080";
 4→
 5→export async function fetchRepos(): Promise<Repository[]> {
 6→  const res = await fetch(`${BASE}/api/repos`);
 7→  if (!res.ok) {
 8→    throw new Error(`Failed to fetch repos: ${res.status}`);
 9→  }
10→  return (await res.json()) ?? [];
11→}
12→
13→export async function addRepo(path: string): Promise<Repository> {
14→  const res = await fetch(`${BASE}/api/repos`, {
15→    method: "POST",
16→    headers: { "Content-Type": "application/json" },
17→    body: JSON.stringify({ path }),
18→  });
19→  if (!res.ok) {
20→    const text = await res.text();
21→    throw new Error(text);
22→  }
23→  return res.json();
24→}
25→
26→export async function deleteRepo(id: number): Promise<void> {
27→  const res = await fetch(`${BASE}/api/repos/${id}`, { method: "DELETE" });
28→  if (!res.ok) {
29→    const text = await res.text();
30→    throw new Error(text);
31→  }
32→}
33→
34→export async function fetchDailyStats(repoPath?: string): Promise<DailyStat[]> {
35→  const params = repoPath ? `?repo=${encodeURIComponent(repoPath)}` : "";
36→  const res = await fetch(`${BASE}/api/daily-stats${params}`);
37→  if (!res.ok) {
38→    throw new Error(`Failed to fetch daily stats: ${res.status}`);
39→  }
40→  return (await res.json()) ?? [];
41→}
42→
43→export async function fetchSessions(repoPath?: string): Promise<Session[]> {
44→  const params = repoPath ? `?repo=${encodeURIComponent(repoPath)}` : "";
45→  const res = await fetch(`${BASE}/api/sessions${params}`);
46→  if (!res.ok) {
47→    throw new Error(`Failed to fetch sessions: ${res.status}`);
48→  }
49→  return (await res.json()) ?? [];
50→}
51→
52→export async function syncData(repoPath?: string): Promise<{ total_found: number; inserted: number }> {
53→  const params = repoPath ? `?repo=${encodeURIComponent(repoPath)}` : "";
54→  const res = await fetch(`${BASE}/api/sync${params}`, { method: "POST" });
55→  if (!res.ok) {
56→    const text = await res.text();
57→    throw new Error(text);
58→  }
59→  return res.json();
60→}
61→

 1→export interface Repository {
 2→  id: number;
 3→  path: string;
 4→  name: string;
 5→  created_at: string;
 6→}
 7→
 8→export interface DailyStat {
 9→  date: string;
10→  agent_lines: number;
11→  human_lines: number;
12→  total_lines: number;
13→  agent_percentage: number;
14→  session_count: number;
15→}
16→
17→export interface Session {
18→  id: number;
19→  repo_path: string;
20→  checkpoint_id: string;
21→  session_id: string;
22→  agent: string;
23→  branch: string;
24→  created_at: string;
25→  prompt: string;
26→  agent_lines: number;
27→  human_added: number;
28→  human_modified: number;
29→  human_removed: number;
30→  total_committed: number;
31→  agent_percentage: number;
32→  input_tokens: number;
33→  output_tokens: number;
34→  api_call_count: number;
35→}
