  1→import {
  2→  BarChart,
  3→  Bar,
  4→  XAxis,
  5→  YAxis,
  6→  CartesianGrid,
  7→  Tooltip,
  8→  ResponsiveContainer,
  9→} from "recharts";
 10→import type { DailyStat } from "../types";
 11→
 12→interface Props {
 13→  data: DailyStat[];
 14→}
 15→
 16→export function DailyDashboard({ data }: Props) {
 17→  if (data.length === 0) {
 18→    return <div className="empty-state">No data yet. Click "Sync" to load.</div>;
 19→  }
 20→
 21→  // Format date for display (MM/DD)
 22→  const chartData = data.map((d) => ({
 23→    ...d,
 24→    dateLabel: d.date.slice(5), // "03-12" format
 25→  }));
 26→
 27→  return (
 28→    <div className="section">
 29→      <div className="section-title">AI / Human Lines by Day (Stacked Bar)</div>
 30→      <div className="section-subtitle">
 31→        Each bar shows total lines committed per day, split by AI-generated and human-written lines
 32→      </div>
 33→      <div className="chart-container">
 34→        <ResponsiveContainer width="100%" height={340}>
 35→          <BarChart data={chartData} margin={{ top: 8, right: 8, left: 0, bottom: 4 }}>
 36→            <CartesianGrid vertical={false} stroke="#e8e8eb" />
 37→            <XAxis
 38→              dataKey="dateLabel"
 39→              tick={{ fill: "#626264", fontSize: 12 }}
