  1→package handlers
  2→
  3→import (
  4→	"encoding/json"
  5→	"entire-dashboard/db"
  6→	gitreader "entire-dashboard/git"
  7→	"log"
  8→	"net/http"
  9→	"path/filepath"
 10→	"strconv"
 11→)
 12→
 13→type Handler struct {
 14→	store *db.Store
 15→}
 16→
 17→func New(store *db.Store) *Handler {
 18→	return &Handler{store: store}
 19→}
 20→
 21→func (h *Handler) GetRepos(w http.ResponseWriter, r *http.Request) {
 22→	repos, err := h.store.GetRepos()
 23→	if err != nil {
 24→		http.Error(w, err.Error(), http.StatusInternalServerError)
 25→		return
 26→	}
 27→	writeJSON(w, repos)
 28→}
 29→
 30→func (h *Handler) AddRepo(w http.ResponseWriter, r *http.Request) {
 31→	var req struct {
 32→		Path string `json:"path"`
 33→	}
 34→	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
 35→		http.Error(w, "invalid request body", http.StatusBadRequest)
 36→		return
 37→	}
 38→	if req.Path == "" {
 39→		http.Error(w, "path is required", http.StatusBadRequest)
 40→		return
 41→	}
 42→
 43→	absPath, err := filepath.Abs(req.Path)
 44→	if err != nil {
 45→		http.Error(w, "invalid path: "+err.Error(), http.StatusBadRequest)
 46→		return
 47→	}
 48→
 49→	name := filepath.Base(absPath)
 50→	repo, err := h.store.AddRepo(absPath, name)
 51→	if err != nil {
 52→		http.Error(w, "failed to add repo: "+err.Error(), http.StatusInternalServerError)
 53→		return
 54→	}
 55→	writeJSON(w, repo)
 56→}
 57→
 58→func (h *Handler) DeleteRepo(w http.ResponseWriter, r *http.Request) {
 59→	idStr := r.PathValue("id")
 60→	id, err := strconv.Atoi(idStr)
 61→	if err != nil {
 62→		http.Error(w, "invalid id", http.StatusBadRequest)
 63→		return
 64→	}
 65→	if err := h.store.DeleteRepo(id); err != nil {
 66→		http.Error(w, "failed to delete repo: "+err.Error(), http.StatusInternalServerError)
 67→		return
 68→	}
 69→	writeJSON(w, map[string]string{"status": "ok"})
 70→}
 71→
 72→func (h *Handler) GetDailyStats(w http.ResponseWriter, r *http.Request) {
 73→	repoPath := r.URL.Query().Get("repo")
 74→	stats, err := h.store.GetDailyStats(repoPath)
 75→	if err != nil {
 76→		http.Error(w, err.Error(), http.StatusInternalServerError)
 77→		return
 78→	}
 79→	writeJSON(w, stats)
 80→}
 81→
 82→func (h *Handler) GetSessions(w http.ResponseWriter, r *http.Request) {
 83→	repoPath := r.URL.Query().Get("repo")
 84→	sessions, err := h.store.GetSessions(repoPath)
 85→	if err != nil {
 86→		http.Error(w, err.Error(), http.StatusInternalServerError)
 87→		return
 88→	}
 89→	writeJSON(w, sessions)
 90→}
 91→
 92→// Sync reads from the git shadow branch and upserts into SQLite.
 93→// If ?repo= is specified, syncs that repo only. Otherwise syncs all registered repos.
 94→func (h *Handler) Sync(w http.ResponseWriter, r *http.Request) {
 95→	repoPath := r.URL.Query().Get("repo")
 96→
 97→	var repos []string
 98→	if repoPath != "" {
 99→		repos = append(repos, repoPath)
100→	} else {
101→		repoList, err := h.store.GetRepos()
102→		if err != nil {
103→			http.Error(w, "failed to list repos: "+err.Error(), http.StatusInternalServerError)
104→			return
105→		}
106→		for _, r := range repoList {
107→			repos = append(repos, r.Path)
108→		}
109→	}
110→
111→	totalFound := 0
112→	totalInserted := 0
113→
114→	for _, rp := range repos {
115→		reader := gitreader.NewReader(rp)
116→		sessions, err := reader.ReadAllSessions()
117→		if err != nil {
118→			log.Printf("sync error for %s: %v", rp, err)
119→			continue
120→		}
121→
122→		inserted := 0
123→		for _, sess := range sessions {
124→			sess.RepoPath = rp
125→			if sess.SessionID == "" {
126→				log.Printf("skip session with empty session_id in %s", rp)
127→				continue
128→			}
129→			exists, err := h.store.SessionExists(sess.SessionID)
130→			if err != nil {
131→				log.Printf("check exists error: %v", err)
132→				continue
133→			}
134→			if exists {
135→				continue
136→			}
137→			if err := h.store.UpsertSession(sess); err != nil {
138→				log.Printf("upsert error: %v", err)
139→				continue
140→			}
141→			inserted++
142→		}
143→		totalFound += len(sessions)
144→		totalInserted += inserted
145→	}
146→
147→	writeJSON(w, map[string]any{
148→		"total_found": totalFound,
149→		"inserted":    totalInserted,
150→		"message":     "sync complete",
151→	})
152→}
153→
154→func writeJSON(w http.ResponseWriter, v any) {
155→	w.Header().Set("Content-Type", "application/json")
156→	json.NewEncoder(w).Encode(v)
157→}
