 5→export async function fetchRepos(): Promise<Repository[]> {
 6→  const res = await fetch(`${BASE}/api/repos`);
 7→  if (!res.ok) {
 8→    throw new Error(`Failed to fetch repos: ${res.status}`);
 9→  }
10→  return (await res.json()) ?? [];
11→}
