26→export async function deleteRepo(id: number): Promise<void> {
27→  const res = await fetch(`${BASE}/api/repos/${id}`, { method: "DELETE" });
28→  if (!res.ok) {
29→    const text = await res.text();
30→    throw new Error(text);
31→  }
32→}
