52→export async function syncData(repoPath?: string): Promise<{ total_found: number; inserted: number }> {
53→  const params = repoPath ? `?repo=${encodeURIComponent(repoPath)}` : "";
54→  const res = await fetch(`${BASE}/api/sync${params}`, { method: "POST" });
55→  if (!res.ok) {
56→    const text = await res.text();
57→    throw new Error(text);
58→  }
59→  return res.json();
60→}
