  1→import {
  2→  BarChart,
  3→  Bar,
  4→  XAxis,
  5→  YAxis,
  6→  CartesianGrid,
  7→  Tooltip,
  8→  ResponsiveContainer,
  9→} from "recharts";
 10→import type { DailyStat } from "../types";
 11→
 12→interface Props {
 13→  data: DailyStat[];
 14→}
 15→
 16→export function DailyDashboard({ data }: Props) {
 17→  if (data.length === 0) {
 18→    return <div className="empty-state">No data yet. Click "Sync" to load.</div>;
 19→  }
 20→
 21→  // Format date for display (MM/DD)
 22→  const chartData = data.map((d) => ({
 23→    ...d,
 24→    dateLabel: d.date.slice(5), // "03-12" format
 25→  }));
 26→
 27→  return (
 28→    <div className="section">
 29→      <div className="section-title">AI / Human Lines by Day (Stacked Bar)</div>
 30→      <div className="section-subtitle">
 31→        Each bar shows total lines committed per day, split by AI-generated and human-written lines
 32→      </div>
 33→      <div className="chart-container">
 34→        <ResponsiveContainer width="100%" height={340}>
 35→          <BarChart data={chartData} margin={{ top: 8, right: 8, left: 0, bottom: 4 }}>
 36→            <CartesianGrid vertical={false} stroke="#e8e8eb" />
 37→            <XAxis
 38→              dataKey="dateLabel"
 39→              tick={{ fill: "#626264", fontSize: 12 }}
 40→              axisLine={{ stroke: "#e8e8eb" }}
 41→              tickLine={false}
 42→            />
 43→            <YAxis
 44→              tick={{ fill: "#626264", fontSize: 12 }}
 45→              axisLine={false}
 46→              tickLine={false}
 47→              width={60}
 48→              tickFormatter={(v: number) => v.toLocaleString()}
 49→            />
 50→            <Tooltip content={<CustomTooltip />} />
 51→            <Bar dataKey="agent_lines" name="AI Lines" stackId="a" fill="#0031D8" />
 52→            <Bar dataKey="human_lines" name="Human Lines" stackId="a" fill="#22A06B" radius={[3, 3, 0, 0]} />
 53→          </BarChart>
 54→        </ResponsiveContainer>
 55→        {/* Inline legend next to chart */}
 56→        <div style={{ display: "flex", gap: 24, paddingLeft: 60, marginTop: 4 }}>
 57→          <LegendItem color="#0031D8" label="AI Lines" />
 58→          <LegendItem color="#22A06B" label="Human Lines" />
 59→        </div>
 60→      </div>
 61→      <div className="meta-info">
 62→        <span>Data source: Entire Checkpoints (Shadow Branch)</span>
 63→        <span>Period: {data[0]?.date} - {data[data.length - 1]?.date}</span>
 64→      </div>
 65→    </div>
 66→  );
 67→}
 68→
 69→function LegendItem({ color, label }: { color: string; label: string }) {
 70→  return (
 71→    <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
 72→      <div style={{ width: 12, height: 12, borderRadius: 2, background: color }} />
 73→      <span style={{ fontSize: 12, color: "#626264" }}>{label}</span>
 74→    </div>
 75→  );
 76→}
 77→
 78→function CustomTooltip({ active, payload, label }: { active?: boolean; payload?: Array<{ value: number; name: string; color: string }>; label?: string }) {
 79→  if (!active || !payload?.length) return null;
 80→
 81→  const ai = payload.find((p) => p.name === "AI Lines")?.value ?? 0;
 82→  const human = payload.find((p) => p.name === "Human Lines")?.value ?? 0;
 83→  const total = ai + human;
 84→  const aiPct = total > 0 ? ((ai / total) * 100).toFixed(1) : "0.0";
 85→
 86→  return (
 87→    <div style={{
 88→      background: "#ffffff",
 89→      border: "1px solid #e8e8eb",
 90→      borderRadius: 6,
 91→      padding: "12px 16px",
 92→      boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
 93→      fontSize: 13,
 94→    }}>
 95→      <div style={{ fontWeight: 600, marginBottom: 8, color: "#1a1a1a" }}>{label}</div>
 96→      <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
 97→        <div style={{ display: "flex", justifyContent: "space-between", gap: 24 }}>
 98→          <span style={{ color: "#0031D8" }}>AI Lines</span>
 99→          <span style={{ fontWeight: 600 }}>{ai.toLocaleString()}</span>
100→        </div>
101→        <div style={{ display: "flex", justifyContent: "space-between", gap: 24 }}>
102→          <span style={{ color: "#22A06B" }}>Human Lines</span>
103→          <span style={{ fontWeight: 600 }}>{human.toLocaleString()}</span>
104→        </div>
105→        <div style={{ borderTop: "1px solid #e8e8eb", paddingTop: 4, marginTop: 4, display: "flex", justifyContent: "space-between" }}>
106→          <span style={{ color: "#626264" }}>AI Ratio</span>
107→          <span style={{ fontWeight: 700, color: "#0031D8" }}>{aiPct}%</span>
108→        </div>
109→      </div>
110→    </div>
111→  );
112→}
